type PaymentService struct {
    paymentRepo repository.PaymentRepository
}

func (s PaymentService) ProcessPayment(ctx context.Context, id uint64, fee float64) (*entity.Payment, error) {
    payment, err := s.paymentRepo.ForID(id).ForStatus("pending").Get(ctx)
    if err != nil {
        return nil, err
    }
    payment.Fee = fee
    payment.Status = "processing"
    result, err := s.paymentRepo.Update(ctx, payment)
    return result, err
}
